import React from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider, useAuth } from './context/AuthContext';
import { CartProvider } from './context/CartContext';

// Importación de tus componentes
import Login from './components/Login';
import PanelCliente from './components/PanelCliente';
import DashboardVendedor from './components/Dashboard';
import Registro from './components/Registro';

// Componente para proteger rutas
const PrivateRoute = ({ children, roleRequired }) => {
    const { user, isAuthenticated, loading } = useAuth();

    // Mientras se verifica si hay un token en localStorage
    if (loading) return (
        <div style={{ display: 'flex', justifyContent: 'center', marginTop: '50px' }}>
            Cargando sesión...
        </div>
    );

    // Si no está logueado, al login
    if (!isAuthenticated) return <Navigate to="/login" />;

    // Si la ruta requiere un rol (vendedor/cliente) y el usuario no lo tiene
    // Nota: Usamos user.rol porque el Contexto suele aplanar el objeto
    if (roleRequired && user?.rol !== roleRequired) {
        return <Navigate to="/" />;
    }

    return children;
};

const AppRoutes = () => {
    const { user, isAuthenticated } = useAuth();

    return (
        <Routes>
            {/* --- RUTAS PÚBLICAS --- */}
            <Route 
                path="/login" 
                element={!isAuthenticated ? <Login /> : <Navigate to="/" />} 
            />
            <Route path="/registro" element={<Registro />} />

            {/* --- RUTA RAÍZ (Home) --- */}
            {/* Redirige automáticamente al panel correcto según el rol al entrar a "/" */}
            <Route path="/" element={
                <PrivateRoute>
                    {user?.rol === 'vendedor' ? <DashboardVendedor /> : <PanelCliente />}
                </PrivateRoute>
            } />

            {/* --- RUTAS PRIVADAS ESPECÍFICAS --- */}
            {/* Estas rutas permiten que navigate('/dashboard') funcione correctamente */}
            <Route path="/dashboard" element={
                <PrivateRoute roleRequired="vendedor">
                    <DashboardVendedor />
                </PrivateRoute>
            } />

            <Route path="/panel-cliente" element={
                <PrivateRoute roleRequired="cliente">
                    <PanelCliente />
                </PrivateRoute>
            } />

            {/* --- RUTAS ADICIONALES --- */}
            <Route path="/tienda" element={
                <PrivateRoute roleRequired="cliente">
                    <PanelCliente />
                </PrivateRoute>
            } />

            {/* Fallback: Cualquier ruta no definida vuelve al inicio */}
            <Route path="*" element={<Navigate to="/" />} />
        </Routes>
    );
};

function App() {
    return (
        <AuthProvider>
            <CartProvider>
                <Router>
                    <AppRoutes />
                </Router>
            </CartProvider>
        </AuthProvider>
    );
}

export default App;
